def generate_questions():
    test_questions = {
        "chunk_id": [],
        "question": []
    }
    for i in tqdm(range(len(data["ids"]))):
        content = data["documents"][i]
        doc_id = data["ids"][i]
        input = {
                "system_prompt": prompt,
                "code_snippet": content
            }
